import { useState } from "react";

const s = {
  overlay: {
    position: "fixed", inset: 0, background: "rgba(0,0,0,0.4)",
    display: "flex", alignItems: "center", justifyContent: "center", zIndex: 200,
  },
  modal: {
    background: "#d9d9d9", borderRadius: 20, padding: "40px 48px",
    width: 520, fontFamily: "'Libre Bodoni', serif",
  },
  title: { fontSize: 30, fontWeight: 400, color: "#5f4a28", marginBottom: 28 },
  label: { fontSize: 20, fontWeight: 400, color: "#5f4a28", marginBottom: 6, display: "block" },
  input: {
    width: "100%", height: 36, borderRadius: 20, border: "none",
    padding: "0 14px", fontSize: 18, fontFamily: "'Libre Bodoni', serif",
    color: "#5f4a28", outline: "none", marginBottom: 20, boxSizing: "border-box",
  },
  textarea: {
    width: "100%", height: 60, borderRadius: 20, border: "none",
    padding: "10px 14px", fontSize: 18, fontFamily: "'Libre Bodoni', serif",
    color: "#5f4a28", outline: "none", marginBottom: 28, boxSizing: "border-box", resize: "none",
  },
  footer: { display: "flex", justifyContent: "space-between", gap: 16 },
  btnCancel: {
    flex: 1, height: 45, borderRadius: 20, border: "none", background: "#fff",
    fontFamily: "'Libre Bodoni', serif", fontSize: 20, color: "#5f4a28", cursor: "pointer",
  },
  btnAdd: {
    flex: 1, height: 45, borderRadius: 20, border: "none", background: "#5f4a28",
    fontFamily: "'Libre Bodoni', serif", fontSize: 20, color: "#ffe5bd", cursor: "pointer",
  },
};

export default function AddServiceModal({ onClose, onAdd }) {
  const [form, setForm] = useState({ name: "", price: "", duration: "", description: "" });
  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });

  return (
    <div style={s.overlay} onClick={onClose}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>
        <div style={s.title}>➕ Add New Service</div>
        <label style={s.label}>Service Name</label>
        <input style={s.input} value={form.name} onChange={set("name")} placeholder="e.g. Facial" />
        <label style={s.label}>Price</label>
        <input style={s.input} value={form.price} onChange={set("price")} placeholder="e.g. $50" />
        <label style={s.label}>Duration</label>
        <input style={s.input} value={form.duration} onChange={set("duration")} placeholder="e.g. 60 minutes" />
        <label style={s.label}>Description</label>
        <textarea style={s.textarea} value={form.description} onChange={set("description")} placeholder="Brief description..." />
        <div style={s.footer}>
          <button style={s.btnCancel} onClick={onClose}>Cancel</button>
          <button style={s.btnAdd} onClick={() => { onAdd(form); onClose(); }}>Add</button>
        </div>
      </div>
    </div>
  );
}
